var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"열흘 전","JPN":"10日前","ENG":"Ten days earlier","TWN":"十天前","SCN":"十天前","DEU":"Ten days earlier","FRA":"Ten days earlier"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"관리국 직할 도시 <color=#ffd34c>샤레이드</color>\\n이스트 시티, 코핀 컴퍼니 샤레이드 지부.","JPN":"管理局直轄都市<color=#ffd34c>シャレード</color>\\nイーストシティ、コフィンカンパニーシャレード支部","ENG":"[[","TWN":"管理局直轄城市<color=#ffd34c>查雷德</color>\\n東城，科芬公司查雷德分部。","SCN":"管理局直辖城市<color=#ffd34c>查雷德</color>\\n东城，科芬公司查雷德分部。","DEU":"[[","FRA":"[["},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 그동안 다들 너무너무 고생 많았어!","JPN":"みんな、今まで本当にお疲れ様！","ENG":"All right, great job hanging in there, everyone!","TWN":"來吧，這段時間大家都辛苦了！"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그럼~ 펠리세트, 라이카 두 사람의 퇴원식을 기념하면서 다 같이~!","JPN":"じゃあ、フェリセットとライカ、2人の退院を祝う意味で～","ENG":"And now, to celebrate Félicette and Laika finally being discharged...!","TWN":"那麼～為了紀念費莉塞特和萊卡兩人的出院儀式，大家一起～"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"건배!","JPN":"乾杯！","ENG":"Cheers!","TWN":"乾杯!"},"stage":{"bg":"SKY_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……라고는 하지만 역시 샤레이드 지부에 저희뿐이라서 썰렁하네요.","JPN":"……とはいえ、やっぱりシャレード支部に私たちだけというのも寂しいですね。","ENG":"Though, with just us here at the Charade branch, it feels a bit empty.","TWN":"……雖然這麼說，但畢竟只有我們在查雷德分部，還是有點冷清啊。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하하, 그거야 어쩔 수 없잖아……?","JPN":"はは、それは仕方ないでしょ……？","ENG":"Haha, well, it can't be helped...","TWN":"哈哈，沒辦法了。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"건틀렛 리그가 끝나자마자, 숨돌릴 틈 없이 커다란 사건들이 연달아 터져버렸으니까.","JPN":"ガントレットリーグが終わるや否や、一息つく間もなく大きな事件が連続で起きたんだから。","ENG":"Right after the Gauntlet League ended, one huge incident after another hit us without a break.","TWN":"聖鎧聯賽剛結束，接連不斷的大事件讓人喘不過氣來。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"바로 전날, 시상식까지 멀쩡하던 샤레이드 시니어가 살해되질 않나…….","JPN":"授賞式までピンピンしてたシャレードのシニアが翌朝死体で発見されたり……","ENG":"Just the day before, the Charade Senior was alive and well at the award ceremony... then suddenly he's murdered...","TWN":"就在前一天，原本在頒獎典禮上還好好的查雷德Senior被殺了。"},"stage":{"bg":"CHARADE2_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"하늘에서 커다란 눈이 나타나더니, 갑자기 사람들이 공중으로 끌려가질 않나…….","JPN":"空に大きな目が現れて、突然人々が宙に浮かされたり……","ENG":"Then a giant eye appeared in the sky, and people started getting pulled up into the air...","TWN":"天空中突然出現了一隻巨大的眼睛，接著人們就被吸到了空中。"},"stage":{"bg":"MS_1203","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"게다가 이번에는 관리 경계 구역에 커다란 우주선이 나타났다면서?","JPN":"しかも今度は管理警戒区域に巨大宇宙船が現れたでしょう？","ENG":"And now there's talk of a massive spaceship showing up in the perimeter zone?","TWN":"而且這次在管理警戒區出現了一艘巨大的太空船？"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"대체 세상이 어떻게 돌아가는 건지, 참…….","JPN":"いったい世の中どうなってるのか、まったく……","ENG":"Seriously, what is even happening in the world anymore...?","TWN":"到底這個世界是怎麼回事，真是……"},"stage":{"bg":"MS_1407","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"뭐, 아무튼 사건들을 수습하기 위해, 사장님께서 로터스에 남기로 결정하셨잖아?","JPN":"まあ、とにかく事件の収拾のために社長がロータスに残ることになったじゃない。","ENG":"Anyway, to deal with all that, Boss decided to stay behind in Lotus, right?","TWN":"總之，為了處理這些事件，老闆決定留在洛德斯，對吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래서 두 사람의 퇴원을 기념해서, 일상으로 돌아온 걸 축하하는 자리를 준비해 봤어.","JPN":"だから2人の退院を記念して、日常に戻ったことを祝う場を作ってみたの。","ENG":"So I thought we'd take this chance to celebrate your discharge... and your return to normal life.","TWN":"所以為了紀念兩人出院，準備了一個慶祝回歸日常的場合。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"일상이라……. 그리운 단어네요.","JPN":"日常……懐かしい響きです。","ENG":"\\"Normal life\\"... It's been a long time since I've heard those words.","TWN":"日常啊……真是懷念的詞語呢。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그동안 이런저런 사건에 휘말려서 정신없이 달려오긴 했죠.","JPN":"しばらくの間、色んな事件に巻き込まれてがむしゃらに走ってきましたからね。","ENG":"We really have been rushing nonstop, getting caught up in one incident after another.","TWN":"這段時間捲入了各種事件，忙得不可開交。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"후후, 그러게.","JPN":"ふふ、そうだね。","ENG":"Haha... yeah, it's been a wild ride.","TWN":"呵呵，是啊。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"기억나? 비록 시작은 불법 침입이었지만, 이곳에서 카나리아 스쿼드의 꿈이 시작됐다구?","JPN":"覚えてる？　最初は違法侵入だったけど、ここでカナリア・スクワッドの夢が始まったんだよ？","ENG":"Remember? We technically broke in here at the start, but this is where the dream of the Canary Squad began.","TWN":"還記得嗎？雖然開始是非法入侵，但金絲雀小隊的夢想就是從這裡開始的喔？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이제 그 꿈을 이루었으니까, 또다시 새로운 목표를 향해 정진할 때가 아닐까?","JPN":"もうその夢も叶ったことだし、また新しい目標に向かって精進する時じゃないかな？","ENG":"Now that we've made that dream come true... maybe it's time to aim for something new.","TWN":"既然已經實現了那個夢想，是時候再次朝著新的目標前進了吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……꿈?","JPN":"……夢？","ENG":"...A dream?","TWN":"……夢？"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오, 꿈도 크다.","JPN":"おお、夢がデカいな。","ENG":"Wow, you got big dreams.","TWN":"噢，你的夢想真遠大。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래도 응원해 줄게. 여기 꼬맹이도 꿈이 참 허무맹랑하걸랑.","JPN":"でも応援するよ。こいつもとんでもない夢を持ってるしな。","ENG":"But I'll root for ya. You see, that kid over there also has big dreams.","TWN":"不過我還是會替你加油，我們這個小鬼也有遠大的夢想喔。"},"stage":{"bg":"ROOFTOP2_NIGHT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};